// Source generation context
[JsonSerializable(typeof(OrderDto))]
[JsonSerializable(typeof(List<OrderDto>))]
[JsonSerializable(typeof(PagedResult<OrderDto>))]
[JsonSourceGenerationOptions(
    PropertyNamingPolicy = JsonKnownNamingPolicy.CamelCase,
    DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull)]
internal partial class AppJsonContext : JsonSerializerContext { }

// Register globally
builder.Services.ConfigureHttpJsonOptions(opt =>
    opt.SerializerOptions.TypeInfoResolverChain.Insert(0, AppJsonContext.Default));

// Custom converter cho DateOnly
public class DateOnlyConverter : JsonConverter<DateOnly>
{
    public override DateOnly Read(ref Utf8JsonReader r, Type t, JsonSerializerOptions o)
        => DateOnly.ParseExact(r.GetString()!, "yyyy-MM-dd");
    public override void Write(Utf8JsonWriter w, DateOnly v, JsonSerializerOptions o)
        => w.WriteStringValue(v.ToString("yyyy-MM-dd"));
}

// Utf8JsonWriter — stream trực tiếp, zero intermediate string
async Task WriteOrdersAsync(
    IAsyncEnumerable<Order> orders, PipeWriter pipe, CancellationToken ct)
{
    using var writer = new Utf8JsonWriter(pipe);
    writer.WriteStartArray();
    await foreach (var o in orders.WithCancellation(ct))
    {
        writer.WriteStartObject();
        writer.WriteNumber("id", o.Id);
        writer.WriteString("status", o.Status);
        writer.WriteEndObject();
        await pipe.FlushAsync(ct);
    }
    writer.WriteEndArray();
    await writer.FlushAsync(ct);
}
